    /// <summary>
    /// Возвращает или инициализирует имя группы.
    /// </summary>
    public string Name { get; init; } = string.Empty;

    /// <summary>
    /// Возвращает или инициализирует путь к изображению группы.
    /// </summary>
    public string ImageUrl { get; init; } = string.Empty;

    /// <summary>
    /// Возвращает или инициализирует описание.
    /// </summary>
    public string Description { get; init; } = string.Empty;

    /// <summary>
    /// Возвращает или инициализирует позиции в группе.
    /// </summary>
    public ServicePosition[] ServicePositions { get; init; } = [];

    /// <summary>
    /// Возвращает все группы.
    /// </summary>
    public static ServiceGroup[] ServiceGroups { get; } = [
        new ()
        {
            //  Design
            Key = 0,
            Name = "Проектирование и документация",
            ImageUrl = "/images/services/groups/design.png",
            Description = "Разработка полной технической и конструкторской документации для подвижного состава, стендов, оборудования и узлов, обеспечивающая соответствие нормативам, технологичность производства и готовность к сертификации.",
            ServicePositions = [
                new()
                {
                    Key = 0,
                    Name = "Пассажирские вагоны",
                    ImageUrl = "/images/services/positions/000-000.png",
                    Description = "Проектирование конструкций и систем пассажирских железнодорожных вагонов с учётом требований комфорта, безопасности, эргономики и сертификационных стандартов, включая кузов, интерьер и инженерные подсистемы.",
                    HtmlContent = "<p>Проектирование пассажирских вагонов — это многоуровневый инженерный процесс, направленный на создание подвижного состава, отвечающего современным требованиям комфорта, безопасности, надёжности и технологичности. Каждый вагон разрабатывается с учётом назначения: от пригородных поездов до спальных вагонов дальнего следования. Конструкторская работа начинается с анализа нормативных требований и технического задания заказчика. Уже на ранних этапах учитываются параметры платформ, радиусы кривых, климатические условия эксплуатации и стандарты межгосударственного взаимодействия. Это обеспечивает возможность дальнейшей эксплуатации вагонов в разных странах, на различных типах путей и при широком диапазоне температур.</p> <p>Функциональное проектирование включает в себя компоновку внутренних пространств с расчётом на максимальную эффективность использования площади. Особое внимание уделяется эргономике: расположению кресел, спальных мест, санитарных блоков и проходов. Каждое конструктивное решение проходит согласование с эксплуатационными требованиями и санитарно-гигиеническими нормами. Отдельно прорабатываются требования к универсальности планировок, что особенно важно для вагонов, предназначенных для международных перевозок. Инженеры также учитывают сценарии перемещения маломобильных пассажиров и обеспечивают доступность всех ключевых элементов инфраструктуры внутри вагона. На этапе планировки внутреннего пространства проводится цифровое моделирование для предварительной оценки удобства и компоновки оборудования.</p> <p>Конструктивная часть проектирования охватывает кузов, тележки, системы крепления, силовые элементы и антикоррозионную защиту. Кузов разрабатывается с учётом требований по прочности, аэродинамике, массе и тепловым деформациям. Расчёты выполняются с использованием современных средств компьютерного моделирования и конечно-элементного анализа. Используемые материалы — чаще всего низколегированные стали и алюминиевые сплавы — подбираются с учётом климатической зоны, частоты эксплуатации и требований к весу. В конструкции обязательно закладываются возможности ревизии, технического обслуживания и быстрой замены ключевых узлов. Применение сварных и клеевых соединений подбирается в зависимости от функциональной нагрузки. Конструкция учитывает также возможные удары, вибрации и динамические нагрузки при движении состава.</p> <p>Отдельное направление — разработка инженерных систем: отопление, вентиляция, кондиционирование, освещение, энергоснабжение, водоснабжение и пожарная сигнализация. Эти подсистемы проектируются как часть общей архитектуры вагона, с учётом их взаимодействия между собой и с инфраструктурой станции или локомотива. Электрооборудование размещается в защищённых зонах и предусматривает быстрое подключение, диагностику и замену. Все элементы проектируются с учётом пожарной безопасности, норм электромагнитной совместимости и устойчивости к перепадам напряжения. Проект предусматривает использование модульных решений, облегчающих обслуживание и модернизацию. При необходимости разрабатываются резервные схемы питания и аварийного освещения. Также учитывается возможность интеграции цифровых систем, в том числе видеонаблюдения, диспетчеризации и связи с пассажирами.</p> <p>Особое внимание уделяется шумо- и виброизоляции, теплоизоляции, защите от влаги и пыли. Проектирование включает в себя выбор материалов, которые обеспечивают акустический комфорт и устойчивость к климатическим факторам. Проводятся акустические расчёты и моделирование резонансных частот. Системы герметизации люков, дверей и окон разрабатываются с применением современных уплотнителей. Материалы отделки и конструктивные элементы проходят испытания на воспламеняемость, выделение вредных веществ и устойчивость к истиранию. Технические решения направлены на достижение максимального срока службы при минимальных затратах на обслуживание. Поверхности вагонов и элементы интерьера подбираются с учётом требований к санитарной обработке и антивандальной защите. Это особенно важно для вагонов, работающих в интенсивных пассажиропотоках.</p> <p>Важной частью проектирования является подготовка полного комплекта конструкторской документации, включающего чертежи, спецификации, расчёты и пояснительные записки. Вся документация формируется в соответствии с ЕСКД, ГОСТ и требованиями сертифицирующих органов. Чертежи сопровождаются электронными моделями, что облегчает процесс согласования и производства. Документация может включать как полный комплект на весь вагон, так и разбивку на функциональные узлы: кузов, интерьер, инженерные системы. При необходимости выполняется адаптация под цифровую PLM-среду заказчика. Конструкторские решения проходят внутреннюю экспертизу, согласование с производственными службами и, при необходимости, ревизию по результатам технологических анализов. Также формируются эксплуатационные паспорта и рекомендации по техническому обслуживанию.</p> <p>На завершающем этапе проект реализуется в виде опытного образца и проходит испытания на соответствие нормативам. В процессе производства и испытаний собирается обратная связь, которая используется для доработки конструкции и документации. Возможна адаптация проекта под международные стандарты (например, TSI в ЕС). После успешной валидации изделие запускается в серийное производство или передаётся заказчику для индивидуального изготовления. Команда проектировщиков может сопровождать процесс внедрения, участвовать в пусконаладке и анализе эксплуатационных показателей. Такой подход позволяет получить не просто чертежи, а работоспособное, проверенное и готовое к эксплуатации решение.</p>",
                },
                new()
                {
                    Key = 1,
                    Name = "Грузовые вагоны",
                    ImageUrl = "/images/services/positions/000-001.png",
                    Description = "Разработка конструкций для перевозки различных типов грузов, включая платформы, полувагоны, цистерны и специализированные составы, с акцентом на прочность, грузоподъёмность и соответствие отраслевым стандартам.",
                    HtmlContent = "<p>Проектирование грузовых вагонов требует комплексного инженерного подхода, учитывающего специфику перевозимых грузов, условия эксплуатации, требования к надёжности и соответствие нормативной базе. Каждый тип грузового вагона — будь то полувагон, платформа, цистерна или хоппер — создаётся под конкретные задачи и стандарты эксплуатации. На начальном этапе проводится анализ грузопотоков, географии маршрутов, температурных режимов и технических ограничений инфраструктуры. Это позволяет заложить в проект прочную конструктивную основу и определить допустимые нагрузки на ось, массу тары и габариты. Кроме того, важно предусмотреть возможность взаимодействия вагона с различными средствами погрузки и выгрузки, в том числе автоматизированными.</p> <p>Одной из ключевых задач является подбор и конструирование кузова, который обеспечивает не только размещение груза, но и его сохранность в пути. Для этого используются как цельнометаллические, так и каркасно-панельные конструкции с защитой от влаги, пыли, механических повреждений и агрессивной среды. Типовая конфигурация может включать боковые или торцевые двери, люки, сливные устройства, крышки и амортизаторы. Отдельно прорабатываются элементы жёсткости и усиления, а также возможность крепления груза в соответствии с правилами перевозки. Проект учитывает как возможности ручной загрузки, так и механизированной, с учётом наличия кранов, грейферов и конвейеров на терминалах. Также предусматривается удобство для очистки и технического обслуживания внутреннего пространства.</p> <p>Подвеска и тележки — важнейшие элементы грузового вагона, отвечающие за его плавность хода, надёжность и безопасность. Они проектируются с расчётом на допустимую нагрузку, динамику движения и стойкость к износу. В зависимости от типа вагона могут использоваться двухосные и четырёхосные тележки различных серий. Обязательной частью проектирования является расчёт вибраций, усталостной прочности и параметров движения на участках с различным профилем пути. Также рассматриваются вопросы уравновешивания нагрузки между осями, особенно при неравномерной загрузке. Кроме того, учитываются требования к взаимодействию с тормозной системой состава и возможность применения автоматических тормозных систем.</p> <p>Современные проекты всё чаще включают элементы автоматизации и цифровизации. Это могут быть датчики нагрузки, системы мониторинга положения, контроля вскрытия люков, контроля температуры или состояния груза. Такие решения требуют внедрения дополнительных кабельных трасс, источников питания и модулей связи. Уже на стадии проектирования важно предусмотреть резервные каналы, защищённые зоны размещения электроники и устойчивость компонентов к вибрациям и климатическим условиям. Электронные компоненты проектируются с учётом быстрого обслуживания и замены, без необходимости разборки основных конструктивных узлов. Такие дополнения повышают интеллектуальный уровень вагона и его ценность в логистических цепочках.</p> <p>Материалы конструкции отбираются с учётом условий эксплуатации: устойчивость к коррозии, нагрузкам, абразивному воздействию и перепадам температур. Наиболее распространены низколегированные стали, защищённые специальными лакокрасочными покрытиями или цинковыми слоями. Возможны варианты с использованием алюминия и композитов в неответственных зонах. Покрытия разрабатываются с учётом агрессивности среды — от обычных маршрутов до химически активных или прибрежных участков. Также анализируется поведение материалов при длительном воздействии статических и переменных нагрузок. Производится расчёт остаточного ресурса и закладываются меры по его увеличению, включая возможность замены отдельных элементов без полной разборки вагона.</p> <p>Конструкторская документация включает в себя полный комплект чертежей, расчётов, спецификаций и пояснительных записок. Каждый проект проходит внутреннюю проверку, согласование с производственными цехами, сертифицирующими организациями и, при необходимости, заказчиком. Документация формируется в цифровом виде с привязкой к моделям САПР, что облегчает управление изменениями, сопровождение производства и контроль качества. Дополнительно могут разрабатываться электронные паспорта вагона, в которых фиксируются параметры, даты обслуживания, проведённые ремонты и статус сертификации. При необходимости документы подготавливаются для интеграции с внешними информационными системами логистики или учёта.</p> <p>После завершения проектирования создаются опытные образцы или макеты для проверки технических решений. В рамках приёмочных испытаний оцениваются прочность, надёжность, маневренность, герметичность и удобство эксплуатации. При необходимости вносятся корректировки в чертежи и перечни материалов. Также возможна адаптация проекта под требования зарубежных рынков — по ширине колеи, сцепке, тормозным системам и знакам маркировки. Готовое изделие после испытаний и сертификации может быть передано в серийное производство, включая сопровождение и техническую поддержку на этапе внедрения. Такой подход позволяет обеспечить не только выпуск конструкции, но и её реальную готовность к эксплуатации в жёстких условиях грузоперевозок.</p>",
                },
                new()
                {
                    Key = 2,
                    Name = "Тележки и сцепные устройства",
                    ImageUrl = "/images/services/positions/000-002.png",
                    Description = "Проектирование ходовых частей и узлов соединения вагонов, включая тележки, буксы, рессоры, автосцепки и амортизаторы, с обеспечением надёжности, устойчивости хода и совместимости с различными типами подвижного состава.",
                    HtmlContent = "<p>Проектирование тележек и сцепных устройств представляет собой важнейшее направление в создании надёжного и безопасного подвижного состава. Тележка — это несущий элемент, обеспечивающий опору вагона, передачу вертикальных и горизонтальных нагрузок, а также реализацию плавного и устойчивого хода. Сцепные устройства, в свою очередь, обеспечивают механическое соединение между вагонами и передачу тяговых усилий поезда. Эти два компонента непосредственно влияют на эксплуатационные характеристики, безопасность движения и комфорт пассажиров. Проектирование начинается с анализа технических требований, включая тип вагона, максимально допустимую нагрузку на ось, радиусы кривых, скорости движения и условия эксплуатации.</p> <p>Конструкция тележки включает раму, буксы, рессорное подвешивание, амортизаторы, тормозное оборудование и элементы крепления колёсных пар. Каждая из этих подсистем должна быть рассчитана на многократные нагрузки, вибрации и удары, возникающие в процессе движения. В современных проектах широко используются двухосные тележки различных серий, соответствующие требованиям ГОСТ, МПС и TSI. Инженеры выполняют прочностные и динамические расчёты, определяют точки концентрации напряжений, анализируют поведение конструкции при различных скоростях и нагрузках. Особое внимание уделяется конструкции букс и элементам демпфирования, от которых зависит устойчивость движения и уровень вибраций. Также рассчитывается угол поворота тележки в кривых участках и взаимодействие с рельсовым путём.</p> <p>Сцепные устройства проектируются с учётом передаваемых усилий при трогании, торможении и аварийных режимах. Наиболее распространённой является автосцепка, которая позволяет автоматически соединять вагоны и гасить динамические удары. Конструкция включает корпус, замковые устройства, поглощающие аппараты и элементы привода. На этапе проектирования проводится расчёт прочности элементов сцепки, анализ ударных нагрузок и определение оптимальных характеристик поглотителей энергии. Также разрабатываются элементы, обеспечивающие безопасность при расцепке и защиту от самопроизвольного разъединения. В зависимости от типа подвижного состава могут применяться разные стандарты сцепления, в том числе совместимые с зарубежными системами.</p> <p>Важной задачей является обеспечение взаимозаменяемости и ремонтопригодности узлов тележек и сцепных устройств. Конструкции разрабатываются с учётом существующей ремонтной базы, наличия оборудования и инструмента на депо. Узлы проектируются модульно, что упрощает их замену и обслуживание. Применяются стандартные посадочные размеры, резьбовые соединения, быстросъёмные элементы. Допускается возможность применения альтернативных материалов при ремонте без ухудшения характеристик. Документация включает указания по техническому обслуживанию, периодичности проверок, допускам износа и методам восстановления работоспособности. Это снижает затраты на жизненный цикл изделия и повышает его эксплуатационную готовность.</p> <p>Особое внимание уделяется технологичности производства. Конструкции тележек и сцепных устройств адаптируются под существующее оборудование на машиностроительных предприятиях. Используются сварные и литьевые компоненты, элементы холодной и горячей штамповки, а также механической обработки. Оптимизируется количество деталей и типоразмеров, снижается вес без ущерба прочности. Внедрение цифровых моделей (CAD), автоматизированной сборки и контроля качества позволяет обеспечить точность и стабильность параметров. На этапе подготовки производства разрабатываются оснастка, контрольные шаблоны и методы испытаний. Это ускоряет переход от проектирования к изготовлению и снижает брак.</p> <p>Проектирование сопровождается разработкой полного комплекта технической документации: чертежей, спецификаций, расчётных пояснений и инструкций по сборке. Документация создаётся в соответствии с ЕСКД и международными стандартами, с возможностью интеграции в PLM-системы заказчика. Также формируются 3D-модели для визуального анализа и проверки сборки, а при необходимости — анимации для демонстрации работы механизмов. Все элементы проходят проверку на технологичность, соответствие техническому заданию и возможность сертификации. При необходимости проводится согласование с внешними экспертными организациями и сертифицирующими органами.</p> <p>После завершения проектирования тележки и сцепные устройства проходят лабораторные и стендовые испытания, включая тесты на прочность, износостойкость, устойчивость к ударным нагрузкам и вибрации. Проверяется точность посадки, взаимодействие с другими элементами вагона, надёжность сцепления и поведение в аварийных режимах. На основе результатов испытаний возможно внесение корректировок в конструкцию. Готовые изделия проходят сертификацию и могут быть запущены в серийное производство. Проектная команда при необходимости сопровождает внедрение, участвует в пусконаладке и сборе данных в реальной эксплуатации. Такой подход обеспечивает высокое качество, надёжность и адаптацию изделий к условиям современного железнодорожного транспорта.</p>",
                },
                new()
                {
                    Key = 3,
                    Name = "Вагонное оборудование и системы",
                    ImageUrl = "/images/services/positions/000-003.png",
                    Description = "Проектирование внутренних и внешних технических систем вагонов: отопление, вентиляция, кондиционирование, освещение, системы водоснабжения, управления дверями и энергоснабжения, с интеграцией в общую архитектуру подвижного состава.",
                    HtmlContent = "<p>Проектирование вагонного оборудования и систем представляет собой сложный инженерный процесс, охватывающий внутренние и внешние подсистемы вагона, обеспечивающие его полноценную работу, безопасность, комфорт и соответствие нормативным требованиям. Каждая система проектируется с учётом взаимодействия с другими компонентами вагона, а также условий эксплуатации на различных маршрутах. Начальным этапом является анализ требований к функциональности: тип перевозок, климатические условия, энергообеспечение, продолжительность рейсов, наличие инфраструктурных ограничений. На основании этих данных формируется архитектура вагонных систем, включающая инженерные, управляющие и обеспечивающие подсистемы.</p> <p>Одной из важнейших задач проектирования является разработка системы отопления, вентиляции и кондиционирования (ОВК). Эти компоненты обеспечивают поддержание комфортных условий для пассажиров при любых внешних температурах. В проект закладываются схемы распределения воздуха, подбор нагревательных и охлаждающих элементов, управление температурой и влажностью. Отдельное внимание уделяется бесшумности, энергоэффективности и гигиеническим требованиям. Используются как централизованные, так и индивидуальные модули с автоматическим управлением. В зависимости от класса вагона возможна дифференциация по зонам с индивидуальными настройками. Все компоненты проходят расчёт на тепловую нагрузку и проверку на устойчивость к вибрациям и загрязнениям.</p> <p>Освещение и электроснабжение — ещё один ключевой элемент оборудования. Системы разрабатываются с учётом надёжности, устойчивости к перепадам напряжения, возможности резервного питания. Используются современные источники света — светодиоды, встроенные в потолочные и настенные панели, с управлением яркостью и автоматическим включением. Электропитание обеспечивается от локомотивного источника, аккумуляторов и, при необходимости, генераторов. Все компоненты защищены от коротких замыканий, перегрузок и скачков. Разрабатываются схемы кабельных трасс, блоки распределения, автоматические выключатели и модули диагностики. Вся система интегрируется с другими компонентами, включая охранную сигнализацию, связь и информационные табло.</p> <p>Водоснабжение и санитарные системы включают в себя баки для питьевой воды, сливные устройства, насосы, системы подогрева и фильтрации. Все компоненты подбираются с учётом условий эксплуатации, частоты использования и санитарных требований. Используются материалы, устойчивые к коррозии, воздействию дезинфицирующих средств и перепадам температур. Канализационные системы разрабатываются с учётом ограничений на сливы, герметичности и удобства обслуживания. Отдельно проектируются системы контроля наполненности баков, индикаторы и аварийные клапаны. Компоновка оборудования предусматривает простоту доступа для технического персонала и быструю замену изнашиваемых узлов.</p> <p>Системы управления дверями и безопасность входят в состав критически важных подсистем. Они обеспечивают контроль открытия и закрытия дверей, блокировки при движении, световую и звуковую сигнализацию. Применяются пневматические, электромеханические и ручные приводы с датчиками положения и системами диагностики. Также разрабатываются механизмы аварийного открывания, устойчивые к внешнему воздействию. В современных проектах предусматривается интеграция с видеонаблюдением, системой контроля доступа и центральной системой управления вагона. Все элементы проходят испытания на надёжность, устойчивость к климатическим условиям и долговечность.</p> <p>Дополнительные системы, такие как климат-контроль, видеонаблюдение, информационные панели, Wi-Fi и системы связи, разрабатываются как модульные элементы, легко встраиваемые в общую архитектуру. Их проектирование ориентировано на совместимость с существующими стандартами связи, малое энергопотребление и простоту настройки. Устройства проектируются с учётом ограниченного пространства, условий вибрации, пыли и возможного вандализма. Также предусматриваются функции удалённой диагностики, журналирования событий и интеграции с платформами верхнего уровня. Подобные элементы особенно важны для вагонов, работающих на дальних маршрутах и в международных составах.</p> <p>Проектирование вагонного оборудования завершается созданием полного пакета документации, включающего компоновочные схемы, электрические чертежи, спецификации, инструкции по монтажу и техническому обслуживанию. Все решения проходят проверку на соответствие ГОСТ, ЕСКД и международным требованиям. При необходимости проводятся натурные испытания, лабораторные тесты и приёмка сертифицирующими организациями. Документация формируется в цифровом виде с привязкой к 3D-моделям вагона и интегрируется в информационные системы предприятия. Это обеспечивает надёжную эксплуатацию, сокращает время обслуживания и повышает уровень безопасности и комфорта пассажиров.</p>",
